1	//! Standalone `lua-rs` interpreter — minimal entry point that exercises the
2	//! full pipeline: `new_state` → `open_libs` → `load_string` → `pcall_k`.
3	//!
4	//! This is intentionally minimal — its job is to surface which `todo!()`
5	//! stubs block real execution, NOT to be a complete Lua interpreter.
6	//!
7	//! Usage:
8	//!   lua-rs '<lua source>'
9	//! Examples:
10	//!   lua-rs 'print("hello")'
11	//!   lua-rs '1+1'
12	
13	use std::panic::{catch_unwind, AssertUnwindSafe};
14	use std::process::ExitCode;
15	
16	use lua_stdlib::auxlib::load_string;
17	use lua_stdlib::init::open_libs;
18	use lua_types::closure::LuaLClosure;
19	use lua_types::error::LuaError;
20	use lua_types::gc::GcRef;
21	use lua_types::upval::UpVal;
22	use lua_types::value::LuaValue;
23	use lua_vm::api::{pcall_k, to_lua_string};
24	use lua_vm::state::{new_state, LuaState};
25	
26	fn file_loader_hook(filename: &[u8]) -> Result<Vec<u8>, LuaError> {
27	    #[cfg(unix)]
28	    let path: std::path::PathBuf = {
29	        use std::os::unix::ffi::OsStrExt;
30	        std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
31	    };
32	    #[cfg(not(unix))]
33	    let path: std::path::PathBuf = {
34	        let s = std::str::from_utf8(filename).map_err(|_| {
35	            LuaError::runtime(format_args!("filename is not valid UTF-8"))
36	        })?;
37	        std::path::PathBuf::from(s)
38	    };
39	    std::fs::read(&path).map_err(|err| {
40	        LuaError::runtime(format_args!(
41	            "cannot open '{}': {}",
42	            String::from_utf8_lossy(filename),
43	            err
44	        ))
45	    })
46	}
47	
48	fn parser_hook(
49	    state: &mut LuaState,
50	    source: &[u8],
51	    name: &[u8],
52	    firstchar: i32,
53	) -> Result<GcRef<LuaLClosure>, LuaError> {
54	    let proto = lua_parse::parse(
55	        state,
56	        lua_parse::DynData::default(),
57	        source,
58	        name,
59	        firstchar,
60	    )?;
61	    let nupvals = proto.upvalues.len();
62	    let mut upvals = Vec::with_capacity(nupvals);
63	    for _ in 0..nupvals {
64	        upvals.push(GcRef::new(UpVal::closed(LuaValue::Nil)));
65	    }
66	    Ok(GcRef::new(LuaLClosure {
67	        proto: GcRef::new(*proto),
68	        upvals,
69	    }))
70	}
71	
72	const MULTRET: i32 = -1;
73	
74	fn render_lua_error(e: &LuaError) -> String {
75	    match e {
76	        LuaError::Runtime(v) | LuaError::Syntax(v) => match v {
77	            LuaValue::Str(s) => format!("{}: {}", e_tag(e), String::from_utf8_lossy(s.as_bytes())),
78	            other => format!("{}: {:?}", e_tag(e), other),
79	        },
80	        LuaError::Memory | LuaError::Error | LuaError::Yield
81	        | LuaError::File | LuaError::Gc => format!("{}", e_tag(e)),
82	    }
83	}
84	
85	fn e_tag(e: &LuaError) -> &'static str {
86	    match e {
87	        LuaError::Runtime(_) => "Runtime",
88	        LuaError::Syntax(_)  => "Syntax",
89	        LuaError::Memory     => "Memory",
90	        LuaError::Error      => "Error",
91	        LuaError::Yield      => "Yield",
92	        LuaError::File       => "File",
93	        LuaError::Gc         => "Gc",
94	    }
95	}
96	
97	fn main() -> ExitCode {
98	    let args_os: Vec<std::ffi::OsString> = std::env::args_os().collect();
99	    if args_os.len() < 2 {
100	        let prog = args_os
101	            .first()
102	            .map(|s| s.to_string_lossy().into_owned())
103	            .unwrap_or_else(|| "lua-rs".to_string());
104	        eprintln!("usage: {} '<lua source>'", prog);
105	        eprintln!("example: {} 'print(\"hello\")'", prog);
106	        return ExitCode::from(2);
107	    }
108	    #[cfg(unix)]
109	    let source: Vec<u8> = {
110	        use std::os::unix::ffi::OsStrExt;
111	        args_os[1].as_bytes().to_vec()
112	    };
113	    #[cfg(not(unix))]
114	    let source: Vec<u8> = args_os[1].to_string_lossy().into_owned().into_bytes();
115	
116	    eprintln!("[1/4] Creating LuaState...");
117	    let result = catch_unwind(AssertUnwindSafe(|| {
118	        let mut state = new_state().ok_or("new_state returned None")?;
119	        state.global_mut().parser_hook = Some(parser_hook);
120	        state.global_mut().file_loader_hook = Some(file_loader_hook);
121	
122	        eprintln!("[2/4] Opening standard library...");
123	        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;
124	
125	        eprintln!("[3/4] Loading source (parse + compile)...");
126	        let status = load_string(&mut state, &source)
127	            .map_err(|e| format!("load_string failed: {}", render_lua_error(&e)))?;
128	        if status != 0 {
129	            let msg = match to_lua_string(&mut state, -1) {
130	                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
131	                _ => "(no error message on stack)".to_string(),
132	            };
133	            return Err(format!(
134	                "Syntax: {} (load_string status={})",
135	                msg, status
136	            ));
137	        }
138	
139	        eprintln!("[4/4] Executing chunk...");
140	        let final_status = pcall_k(&mut state, 0, MULTRET, 0, 0, None)
141	            .map_err(|e| format!("pcall_k failed: {}", render_lua_error(&e)))?;
142	
143	        Ok::<_, String>(final_status)
144	    }));
145	
146	    match result {
147	        Ok(Ok(status)) => {
148	            eprintln!("[ok] execution completed, status={:?}", status);
149	            ExitCode::SUCCESS
150	        }
151	        Ok(Err(msg)) => {
152	            eprintln!("[err] {}", msg);
153	            ExitCode::from(1)
154	        }
155	        Err(panic) => {
156	            let msg = if let Some(s) = panic.downcast_ref::<String>() {
157	                s.clone()
158	            } else if let Some(s) = panic.downcast_ref::<&str>() {
159	                s.to_string()
160	            } else {
161	                "(non-string panic payload)".to_string()
162	            };
163	            eprintln!("[panic] {}", msg);
164	            ExitCode::from(101)
165	        }
166	    }
167	}
168	
169	// ──────────────────────────────────────────────────────────────────────────
170	// PORT STATUS
171	//   source:        (minimal entrypoint; not a port of lua.c — that's Phase F)
172	//   target_crate:  lua-cli
173	//   confidence:    high
174	//   todos:         0
175	//   port_notes:    0
176	//   unsafe_blocks: 0
177	//   notes:         drives new_state → open_libs → load_string → pcall_k.
178	//                  Designed to surface the first todo!() panic on a hello-
179	//                  world program, not to be a complete interpreter.
180	// ──────────────────────────────────────────────────────────────────────────
